@import "tailwindcss";

@theme {
  --color-primary: #8B0000;
  --color-primary-light: #B22222;
  --color-primary-dark: #6B0000;
  --color-secondary: #e63946;
  --color-background: #0a0a0a;
  --color-background-alt: #111111;
  --color-surface: #1a1a1a;
  --color-surface-hover: #252525;
  --color-foreground: #f0f0f0;
  --color-muted: #888888;
  --color-border: #2a2a2a;
  --color-accent: #e63946;
  --color-error: #E05C5C;
  --color-success: #5CB87A;

  --font-heading: 'Playfair Display', Georgia, serif;
  --font-body: 'Inter', system-ui, sans-serif;
  --font-accent: 'Cormorant Garamond', Georgia, serif;
}

@layer base {
  body {
    background-color: #0a0a0a;
    color: #f0f0f0;
    font-family: 'Inter', system-ui, sans-serif;
  }

  ::selection {
    background-color: #8B0000;
    color: #f0f0f0;
  }

  ::-webkit-scrollbar { width: 8px; }
  ::-webkit-scrollbar-track { background: #0a0a0a; }
  ::-webkit-scrollbar-thumb { background: #2a2a2a; border-radius: 4px; }
  ::-webkit-scrollbar-thumb:hover { background: #8B0000; }
}

@layer utilities {
  .glow-red {
    box-shadow: 0 0 20px rgba(139, 0, 0, 0.3), 0 0 40px rgba(139, 0, 0, 0.1);
  }
  .text-glow {
    text-shadow: 0 0 10px rgba(139, 0, 0, 0.5);
  }
  .bg-grid {
    background-image:
      linear-gradient(rgba(139, 0, 0, 0.03) 1px, transparent 1px),
      linear-gradient(90deg, rgba(139, 0, 0, 0.03) 1px, transparent 1px);
    background-size: 40px 40px;
  }
}
